  function loadHistory(){try{var raw=localStorage.getItem('hccColorHistory');if(raw){colorHistory=JSON.parse(raw).filter(function(h){return /^[0-9A-F]{6}$/.test(cleanHex(h))}).map(cleanHex).slice(0,24)}}catch(_){colorHistory=[]}}
